"use client"

import * as React from "react"
import { Button } from "@/components/ui/button"

export interface LemmaBulkActionsBarProps {
  selectedCount: number
  title?: string
  description?: string
  isDeleting?: boolean
  deleteLabel?: string
  clearLabel?: string
  onDeleteSelected?: () => void
  onClearSelection?: () => void
  error?: Error | null
  message?: string | null
}

export function LemmaBulkActionsBar({
  selectedCount,
  title = "Bulk actions",
  description = "Select multiple rows to run a single action across them.",
  isDeleting = false,
  deleteLabel = "Delete selected",
  clearLabel = "Clear selection",
  onDeleteSelected,
  onClearSelection,
  error,
  message,
}: LemmaBulkActionsBarProps) {
  if (selectedCount <= 0 && !error && !message) return null

  return (
    <div className="grid gap-3 rounded-[var(--resource-radius-md)] border border-[color:var(--resource-border)] bg-[var(--resource-surface)] p-4 shadow-sm">
      <div className="flex flex-col gap-3 md:flex-row md:items-center md:justify-between">
        <div className="grid gap-1">
          <div className="text-sm font-medium text-[color:var(--resource-text)]">{title}</div>
          <div className="text-sm text-[color:var(--resource-muted)]">
            {selectedCount > 0
              ? `${selectedCount} record${selectedCount === 1 ? "" : "s"} selected. ${description}`
              : description}
          </div>
        </div>
        {selectedCount > 0 ? (
          <div className="flex items-center gap-2">
            {onClearSelection ? (
              <Button onClick={onClearSelection} variant="ghost">
                {clearLabel}
              </Button>
            ) : null}
            {onDeleteSelected ? (
              <Button disabled={isDeleting} onClick={onDeleteSelected}>
                {isDeleting ? "Deleting…" : deleteLabel}
              </Button>
            ) : null}
          </div>
        ) : null}
      </div>

      {error ? (
        <div className="rounded-md border border-[color:var(--resource-danger-border)] bg-[var(--resource-danger-soft)] px-3 py-2 text-sm text-[color:var(--resource-danger)]">
          {error.message}
        </div>
      ) : null}

      {message ? (
        <div className="rounded-md border border-[color:var(--resource-border-strong)] bg-[var(--resource-surface-alt)] px-3 py-2 text-sm text-[color:var(--resource-text)]">
          {message}
        </div>
      ) : null}
    </div>
  )
}

"use client"

import * as React from "react"
import type { LemmaClient } from "lemma-sdk"
import { useRecord } from "lemma-sdk/react"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"

export interface LemmaRecordDetailsCardProps {
  client: LemmaClient
  podId?: string
  tableName: string
  recordId?: string | null
  fields?: string[]
  title?: string
  description?: string
}

function sentenceCase(value: string): string {
  return value
    .replace(/_/g, " ")
    .replace(/\s+/g, " ")
    .trim()
    .replace(/\b\w/g, (match) => match.toUpperCase())
}

function formatValue(value: unknown): string {
  if (typeof value === "string") return value
  if (typeof value === "number" || typeof value === "boolean") return String(value)
  if (value === null || typeof value === "undefined") return "—"

  try {
    return JSON.stringify(value, null, 2)
  } catch {
    return String(value)
  }
}

export function LemmaRecordDetailsCard({
  client,
  podId,
  tableName,
  recordId,
  fields,
  title,
  description,
}: LemmaRecordDetailsCardProps) {
  const trimmedTableName = tableName.trim()
  const trimmedRecordId = typeof recordId === "string" ? recordId.trim() : ""
  const recordState = useRecord({
    client,
    podId,
    tableName: trimmedTableName,
    recordId: trimmedRecordId || null,
    enabled: trimmedTableName.length > 0 && trimmedRecordId.length > 0,
  })

  const visibleFields = React.useMemo(() => {
    const record = recordState.record
    if (!record) return fields ?? []
    if (fields?.length) return fields
    return Object.keys(record)
      .filter((field) => field !== "created_at" && field !== "updated_at")
      .slice(0, 12)
  }, [fields, recordState.record])

  if (!trimmedTableName || !trimmedRecordId) {
    return (
      <Card>
        <CardHeader>
          <CardTitle>{title ?? "Record Details"}</CardTitle>
          <CardDescription>{description ?? "Select a record to inspect its full payload."}</CardDescription>
        </CardHeader>
      </Card>
    )
  }

  return (
    <Card>
      <CardHeader>
        <div className="flex items-start justify-between gap-3">
          <div className="grid gap-1">
            <CardTitle>{title ?? "Record Details"}</CardTitle>
            <CardDescription>{description ?? "Inspect the selected record with real values."}</CardDescription>
          </div>
          <Button
            disabled={recordState.isLoading}
            onClick={() => {
              void recordState.refresh()
            }}
            variant="outline"
          >
            {recordState.isLoading ? "Refreshing…" : "Refresh"}
          </Button>
        </div>
      </CardHeader>
      <CardContent className="grid gap-4">
        {recordState.error ? (
          <div className="rounded-md border border-[color:var(--resource-danger-border)] bg-[var(--resource-danger-soft)] px-3 py-2 text-sm text-[color:var(--resource-danger)]">
            {recordState.error.message}
          </div>
        ) : null}

        {recordState.isLoading && !recordState.record ? (
          <div className="rounded-md border border-dashed border-[color:var(--resource-border)] bg-[var(--resource-surface-alt)] px-3 py-6 text-sm text-[color:var(--resource-muted)]">
            Loading record details…
          </div>
        ) : null}

        {recordState.record ? (
          <div className="grid gap-3">
            {visibleFields.map((field) => (
              <div key={field} className="rounded-[calc(var(--resource-radius-md)-0.2rem)] border border-[color:var(--resource-border)] bg-[var(--resource-surface-alt)] px-3 py-3">
                <div className="text-xs uppercase tracking-[0.16em] text-[color:var(--resource-subtle)]">{sentenceCase(field)}</div>
                <pre className="mt-2 whitespace-pre-wrap text-sm leading-6 text-[color:var(--resource-text)]">
                  {formatValue(recordState.record?.[field])}
                </pre>
              </div>
            ))}
          </div>
        ) : null}
      </CardContent>
    </Card>
  )
}

"use client"

import * as React from "react"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"

type SortFieldOption = string | { value: string; label: string }
export type LemmaFilterFieldType =
  | "text"
  | "textarea"
  | "number"
  | "boolean"
  | "json"
  | "date"
  | "datetime"
  | "select"
  | "foreign-key"
  | "uuid"
  | (string & {})

export interface LemmaFilterFieldOption {
  value: string
  label: string
  type?: LemmaFilterFieldType
  options?: string[]
}

export interface LemmaFilterCondition {
  id: string
  field: string
  op: string
  value?: string
}

export interface LemmaRecordFiltersBarProps {
  search: string
  onSearchChange: (value: string) => void
  searchPlaceholder?: string
  resultCount?: number
  onRefresh?: () => void
  isRefreshing?: boolean
  sortBy?: string
  onSortByChange?: (value: string) => void
  sortOrder?: "asc" | "desc"
  onSortOrderChange?: (value: "asc" | "desc") => void
  availableSortFields?: SortFieldOption[]
  pageSize?: number
  onPageSizeChange?: (value: number) => void
  pageSizeOptions?: number[]
  availableFilterFields?: LemmaFilterFieldOption[]
  filters?: LemmaFilterCondition[]
  onFiltersChange?: (filters: LemmaFilterCondition[]) => void
  allowSearch?: boolean
  allowFilters?: boolean
  allowSorting?: boolean
  allowPageSizeSelect?: boolean
}

const DEFAULT_PAGE_SIZE_OPTIONS = [10, 25, 50, 100]
const DEFAULT_SORT_VALUE = "__default__"
const FILTERABLE_TEXT_TYPES = new Set(["text", "textarea", "uuid", "foreign-key", "json"])
const FILTERABLE_NUMERIC_TYPES = new Set(["number"])
const FILTERABLE_TEMPORAL_TYPES = new Set(["date", "datetime"])

function createEmptyFilter(field?: LemmaFilterFieldOption): LemmaFilterCondition {
  return {
    id: Math.random().toString(36).slice(2, 10),
    field: field?.value ?? "",
    op: defaultFilterOperator(field?.type),
    value: "",
  }
}

function normalizeSortOptions(options?: SortFieldOption[]): Array<{ value: string; label: string }> {
  if (!options?.length) return []

  return options
    .map((option) => (
      typeof option === "string"
        ? { value: option, label: option }
        : option
    ))
    .filter((option) => option.value.trim().length > 0)
}

function defaultFilterOperator(type?: LemmaFilterFieldType): string {
  if (type === "boolean") return "is"
  if (type === "select") return "is"
  if (FILTERABLE_NUMERIC_TYPES.has(type ?? "")) return "is"
  if (FILTERABLE_TEMPORAL_TYPES.has(type ?? "")) return "is"
  return "contains"
}

function availableOperators(type?: LemmaFilterFieldType): Array<{ value: string; label: string }> {
  if (type === "boolean" || type === "select") {
    return [
      { value: "is", label: "is" },
      { value: "is_not", label: "is not" },
    ]
  }

  if (FILTERABLE_NUMERIC_TYPES.has(type ?? "") || FILTERABLE_TEMPORAL_TYPES.has(type ?? "")) {
    return [
      { value: "is", label: "is" },
      { value: "is_not", label: "is not" },
      { value: "gt", label: "greater than" },
      { value: "gte", label: "greater or equal" },
      { value: "lt", label: "less than" },
      { value: "lte", label: "less or equal" },
      { value: "is_empty", label: "is empty" },
      { value: "is_not_empty", label: "is not empty" },
    ]
  }

  return [
    { value: "contains", label: "contains" },
    { value: "does_not_contain", label: "does not contain" },
    { value: "is", label: "is" },
    { value: "is_not", label: "is not" },
    { value: "starts_with", label: "starts with" },
    { value: "ends_with", label: "ends with" },
    { value: "is_empty", label: "is empty" },
    { value: "is_not_empty", label: "is not empty" },
  ]
}

function operatorNeedsValue(op: string): boolean {
  return op !== "is_empty" && op !== "is_not_empty"
}

export function LemmaRecordFiltersBar({
  search,
  onSearchChange,
  searchPlaceholder = "Search records…",
  resultCount,
  onRefresh,
  isRefreshing = false,
  sortBy = "",
  onSortByChange,
  sortOrder = "asc",
  onSortOrderChange,
  availableSortFields,
  pageSize,
  onPageSizeChange,
  pageSizeOptions = DEFAULT_PAGE_SIZE_OPTIONS,
  availableFilterFields = [],
  filters = [],
  onFiltersChange,
  allowSearch = true,
  allowFilters = true,
  allowSorting = true,
  allowPageSizeSelect = true,
}: LemmaRecordFiltersBarProps) {
  const sortOptions = React.useMemo(
    () => normalizeSortOptions(availableSortFields),
    [availableSortFields],
  )
  const [isFilterEditorOpen, setIsFilterEditorOpen] = React.useState(false)
  const [draftFilters, setDraftFilters] = React.useState<LemmaFilterCondition[]>(filters)

  React.useEffect(() => {
    if (!isFilterEditorOpen) {
      setDraftFilters(filters)
    }
  }, [filters, isFilterEditorOpen])

  const activeFilterCount = filters.filter((filter) => filter.field && (operatorNeedsValue(filter.op) ? (filter.value ?? "").trim().length > 0 : true)).length
  const firstFilterField = availableFilterFields[0]

  return (
    <>
    <div className="flex min-w-0 flex-col gap-3 rounded-[8px] border border-[color:var(--resource-border)] bg-[var(--resource-surface)] p-4 shadow-sm">
      <div className="flex min-w-0 flex-col gap-3 md:flex-row md:items-center">
      {allowSearch ? (
        <div className="min-w-[220px] flex-1">
          <Input
            onChange={(event) => onSearchChange(event.target.value)}
            placeholder={searchPlaceholder}
            value={search}
          />
        </div>
      ) : null}
      {allowFilters && onFiltersChange && availableFilterFields.length > 0 ? (
        <Button
          onClick={() => {
            setDraftFilters(filters.length > 0 ? filters : [createEmptyFilter(firstFilterField)])
            setIsFilterEditorOpen(true)
          }}
          variant="outline"
        >
          Filters{activeFilterCount > 0 ? ` (${activeFilterCount})` : ""}
        </Button>
      ) : null}
      {allowSorting && sortOptions.length > 0 && onSortByChange ? (
        <div className="grid gap-2 md:min-w-[180px]">
          <Select
            value={sortBy || DEFAULT_SORT_VALUE}
            onValueChange={(value) => onSortByChange(value === DEFAULT_SORT_VALUE ? "" : value)}
          >
            <SelectTrigger id="lemma-record-filters-sort-by">
              <SelectValue placeholder="Sort field" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value={DEFAULT_SORT_VALUE}>Default order</SelectItem>
              {sortOptions.map((option) => (
                <SelectItem key={option.value} value={option.value}>
                  {option.label}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
      ) : null}
      {allowSorting && onSortOrderChange ? (
        <div className="grid gap-2 md:min-w-[140px]">
          <Select value={sortOrder} onValueChange={(value) => onSortOrderChange(value as "asc" | "desc")}>
            <SelectTrigger id="lemma-record-filters-sort-order">
              <SelectValue placeholder="Sort order" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="asc">Ascending</SelectItem>
              <SelectItem value="desc">Descending</SelectItem>
            </SelectContent>
          </Select>
        </div>
      ) : null}
      {allowPageSizeSelect && typeof pageSize === "number" && onPageSizeChange ? (
        <div className="grid gap-2 md:min-w-[130px]">
          <Select value={String(pageSize)} onValueChange={(value) => onPageSizeChange(Number(value))}>
            <SelectTrigger id="lemma-record-filters-page-size">
              <SelectValue placeholder="Page size" />
            </SelectTrigger>
            <SelectContent>
              {pageSizeOptions.map((option) => (
                <SelectItem key={option} value={String(option)}>
                  {option} / page
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
      ) : null}
      <div className="flex items-center gap-3">
        {typeof resultCount === "number" ? (
          <p className="text-xs text-[color:var(--resource-muted)]">
            {resultCount} result{resultCount === 1 ? "" : "s"}
          </p>
        ) : null}
        {onRefresh ? (
          <Button disabled={isRefreshing} onClick={onRefresh} variant="outline">
            {isRefreshing ? "Refreshing…" : "Refresh"}
          </Button>
        ) : null}
      </div>
      </div>
      {activeFilterCount > 0 ? (
        <div className="flex flex-wrap gap-2">
          {filters
            .filter((filter) => filter.field && (operatorNeedsValue(filter.op) ? (filter.value ?? "").trim().length > 0 : true))
            .map((filter) => {
              const field = availableFilterFields.find((option) => option.value === filter.field)
              const operator = availableOperators(field?.type).find((option) => option.value === filter.op)
              return (
                <div
                  className="inline-flex items-center gap-2 rounded-full border border-[color:var(--resource-border)] bg-[var(--resource-surface-alt)] px-3 py-1 text-xs text-[color:var(--resource-muted-strong)]"
                  key={filter.id}
                >
                  <span className="font-medium text-[color:var(--resource-text)]">{field?.label ?? filter.field}</span>
                  <span>{operator?.label ?? filter.op}</span>
                  {operatorNeedsValue(filter.op) ? <span>{filter.value}</span> : null}
                </div>
              )
            })}
        </div>
      ) : null}
    </div>
    {isFilterEditorOpen ? (
      <div className="fixed inset-0 z-50 flex items-start justify-center bg-black/20 px-4 py-8 backdrop-blur-[1px]">
        <div className="w-full max-w-5xl rounded-[8px] border border-[color:var(--resource-border)] bg-[var(--resource-surface)] shadow-[0_28px_90px_-40px_var(--resource-shadow-lg)]">
          <div className="flex items-start justify-between gap-4 border-b border-[color:var(--resource-border)] px-6 py-5">
            <div className="grid gap-2">
              <h3 className="text-3xl font-semibold text-[color:var(--resource-text)]">Filter Records</h3>
              <p className="text-sm uppercase tracking-[0.18em] text-[color:var(--resource-muted-strong)]">
                Refine your view by adding conditions
              </p>
            </div>
            <Button
              onClick={() => {
                setDraftFilters(filters)
                setIsFilterEditorOpen(false)
              }}
              variant="ghost"
            >
              Close
            </Button>
          </div>
          <div className="grid gap-4 border-b border-[color:var(--resource-border)] px-6 py-6">
            {draftFilters.map((filter, index) => {
              const field = availableFilterFields.find((option) => option.value === filter.field) ?? firstFilterField
              const operators = availableOperators(field?.type)
              const showValueInput = operatorNeedsValue(filter.op)
              const fieldType = field?.type ?? "text"
              return (
                <div className="grid gap-3 md:grid-cols-[minmax(0,1.3fr)_minmax(180px,0.9fr)_minmax(0,1.6fr)_auto]" key={filter.id}>
                  <Select
                    value={filter.field}
                    onValueChange={(value) => {
                      const nextField = availableFilterFields.find((option) => option.value === value)
                      setDraftFilters((current) => current.map((entry) => (
                        entry.id === filter.id
                          ? {
                              ...entry,
                              field: value,
                              op: defaultFilterOperator(nextField?.type),
                              value: "",
                            }
                          : entry
                      )))
                    }}
                  >
                    <SelectTrigger>
                      <SelectValue placeholder="Field" />
                    </SelectTrigger>
                    <SelectContent>
                      {availableFilterFields.map((option) => (
                        <SelectItem key={option.value} value={option.value}>
                          {option.label}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                  <Select
                    value={filter.op}
                    onValueChange={(value) => {
                      setDraftFilters((current) => current.map((entry) => (
                        entry.id === filter.id
                          ? {
                              ...entry,
                              op: value,
                              value: operatorNeedsValue(value) ? entry.value ?? "" : "",
                            }
                          : entry
                      )))
                    }}
                  >
                    <SelectTrigger>
                      <SelectValue placeholder="Condition" />
                    </SelectTrigger>
                    <SelectContent>
                      {operators.map((option) => (
                        <SelectItem key={option.value} value={option.value}>
                          {option.label}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                  {showValueInput ? (
                    fieldType === "boolean" ? (
                      <Select
                        value={filter.value ?? ""}
                        onValueChange={(value) => {
                          setDraftFilters((current) => current.map((entry) => (
                            entry.id === filter.id ? { ...entry, value } : entry
                          )))
                        }}
                      >
                        <SelectTrigger>
                          <SelectValue placeholder="Value" />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="true">True</SelectItem>
                          <SelectItem value="false">False</SelectItem>
                        </SelectContent>
                      </Select>
                    ) : fieldType === "select" && field?.options?.length ? (
                      <Select
                        value={filter.value ?? ""}
                        onValueChange={(value) => {
                          setDraftFilters((current) => current.map((entry) => (
                            entry.id === filter.id ? { ...entry, value } : entry
                          )))
                        }}
                      >
                        <SelectTrigger>
                          <SelectValue placeholder="Value" />
                        </SelectTrigger>
                        <SelectContent>
                          {field.options.map((option) => (
                            <SelectItem key={option} value={option}>
                              {option}
                            </SelectItem>
                          ))}
                        </SelectContent>
                      </Select>
                    ) : (
                      <Input
                        onChange={(event) => {
                          const value = event.target.value
                          setDraftFilters((current) => current.map((entry) => (
                            entry.id === filter.id ? { ...entry, value } : entry
                          )))
                        }}
                        placeholder="Value"
                        type={fieldType === "number" ? "number" : fieldType === "date" ? "date" : fieldType === "datetime" ? "datetime-local" : "text"}
                        value={filter.value ?? ""}
                      />
                    )
                  ) : (
                    <div className="flex items-center rounded-[8px] border border-dashed border-[color:var(--resource-border)] px-3 text-sm text-[color:var(--resource-muted)]">
                      No value needed
                    </div>
                  )}
                  <Button
                    onClick={() => {
                      setDraftFilters((current) => current.filter((entry) => entry.id !== filter.id))
                    }}
                    variant="ghost"
                  >
                    Remove
                  </Button>
                </div>
              )
            })}
            <button
              className="flex w-full items-center justify-center gap-2 rounded-[8px] border border-dashed border-[color:var(--resource-border)] px-4 py-4 text-base font-medium text-[color:var(--resource-muted-strong)] transition-colors hover:bg-[var(--resource-surface-alt)]"
              onClick={() => {
                setDraftFilters((current) => [...current, createEmptyFilter(firstFilterField)])
              }}
              type="button"
            >
              <span className="text-xl leading-none">+</span>
              Add Condition
            </button>
          </div>
          <div className="flex items-center justify-end gap-3 px-6 py-5">
            <Button
              onClick={() => {
                setDraftFilters(filters)
                setIsFilterEditorOpen(false)
              }}
              variant="ghost"
            >
              Cancel
            </Button>
            <Button
              onClick={() => {
                onFiltersChange?.(
                  draftFilters.filter((filter) => (
                    filter.field.trim().length > 0
                    && (operatorNeedsValue(filter.op) ? (filter.value ?? "").trim().length > 0 : true)
                  )),
                )
                setIsFilterEditorOpen(false)
              }}
            >
              Apply Filters
            </Button>
          </div>
        </div>
      </div>
    ) : null}
    </>
  )
}

"use client"

import * as React from "react"
import type { LemmaClient } from "lemma-sdk"
import { useRecordForm } from "lemma-sdk/react"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { Checkbox } from "@/components/ui/checkbox"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { Textarea } from "@/components/ui/textarea"
import { LemmaForeignKeySelect } from "@/components/lemma/lemma-foreign-key-select"

export interface LemmaRecordFormProps {
  client: LemmaClient
  podId?: string
  tableName: string
  recordId?: string | null
  initialValues?: Record<string, unknown>
  mode?: "auto" | "create" | "update"
  title?: string
  description?: string
  submitLabel?: string
  hiddenFields?: string[]
  fieldOrder?: string[]
  onSubmitted?: (record: Record<string, unknown>) => void
  onCancel?: () => void
  appearance?: "card" | "modal"
  fieldLabels?: Record<string, string>
  fieldDescriptions?: Record<string, string>
  showReset?: boolean
  resetLabel?: string
  cancelLabel?: string
}

function orderFields(
  fields: Array<ReturnType<typeof useRecordForm>["editableFields"][number]>,
  fieldOrder?: string[],
) {
  if (!fieldOrder?.length) return fields

  const indexByName = new Map(fieldOrder.map((name, index) => [name, index]))

  return [...fields].sort((left, right) => {
    const leftIndex = indexByName.get(left.name)
    const rightIndex = indexByName.get(right.name)

    if (typeof leftIndex === "number" && typeof rightIndex === "number") {
      return leftIndex - rightIndex
    }

    if (typeof leftIndex === "number") return -1
    if (typeof rightIndex === "number") return 1
    return left.label.localeCompare(right.label)
  })
}

export function LemmaRecordForm({
  client,
  podId,
  tableName,
  recordId,
  initialValues,
  mode = "auto",
  title,
  description,
  submitLabel = recordId ? "Save changes" : "Create record",
  hiddenFields = [],
  fieldOrder,
  onSubmitted,
  onCancel,
  appearance = "card",
  fieldLabels,
  fieldDescriptions,
  showReset = true,
  resetLabel = "Reset",
  cancelLabel = "Cancel",
}: LemmaRecordFormProps) {
  const hasTableName = tableName.trim().length > 0

  const form = useRecordForm({
    client,
    podId,
    tableName,
    recordId,
    initialValues,
    mode,
    onSubmitSuccess: (record) => onSubmitted?.(record),
  })

  const fields = React.useMemo(() => {
    const visibleFields = form.editableFields.filter((field) => !hiddenFields.includes(field.name))
    return orderFields(visibleFields, fieldOrder)
  }, [fieldOrder, form.editableFields, hiddenFields])

  const handleSubmit = React.useCallback(async (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault()
    await form.submit()
  }, [form])

  if (!hasTableName) {
    return (
      <Card>
        <CardHeader>
          <CardTitle>{title ?? "Registry Record Form"}</CardTitle>
          <CardDescription>
            {description ?? "Select a table to render the generated record form."}
          </CardDescription>
        </CardHeader>
      </Card>
    )
  }

  const header = (
    <div className="grid gap-2">
      <h3 className="text-2xl font-semibold text-[color:var(--resource-text)]">
        {title ?? `${recordId ? "Edit" : "Create"} ${tableName}`}
      </h3>
      <p className="text-sm uppercase tracking-[0.18em] text-[color:var(--resource-muted-strong)]">
        {description ?? "Schema-aware form powered by lemma-sdk/react."}
      </p>
    </div>
  )

  const body = (
    <form className="grid gap-5" onSubmit={handleSubmit}>
      {form.error ? (
        <div className="rounded-md border border-[color:var(--resource-danger-border)] bg-[var(--resource-danger-soft)] px-3 py-2 text-sm text-[color:var(--resource-danger)]">
          {form.error.message}
        </div>
      ) : null}

      {form.isLoadingSchema || form.isLoadingRecord ? (
        <div className="rounded-md border border-dashed border-[color:var(--resource-border)] bg-[var(--resource-surface-alt)] px-3 py-6 text-sm text-[color:var(--resource-muted)]">
          Loading form…
        </div>
      ) : null}

      {!form.isLoadingSchema && !form.isLoadingRecord && fields.length === 0 ? (
        <div className="rounded-md border border-dashed border-[color:var(--resource-border)] bg-[var(--resource-surface-alt)] px-3 py-6 text-sm text-[color:var(--resource-muted)]">
          No editable fields were found for this table.
        </div>
      ) : null}

      {fields.map((field) => {
        const value = form.values[field.name]
        const error = form.fieldErrors[field.name]
        const resolvedLabel = fieldLabels?.[field.name] ?? field.label
        const resolvedDescription = fieldDescriptions?.[field.name] ?? field.column.description
        const commonLabel = (
          <div className="grid gap-2">
            <div className="flex flex-wrap items-center gap-2">
              <Label className="text-sm font-semibold uppercase tracking-[0.12em] text-[color:var(--resource-muted-strong)]" htmlFor={field.name}>
                {resolvedLabel}
                {field.required ? " *" : ""}
              </Label>
              <span className="inline-flex rounded-[6px] bg-[#e8eeff] px-2 py-0.5 text-xs font-medium uppercase tracking-[0.08em] text-[#3e78ff]">
                {field.column.type.toLowerCase()}
              </span>
            </div>
            {resolvedDescription ? (
              <p className="text-sm text-[color:var(--resource-muted)]">{resolvedDescription}</p>
            ) : null}
          </div>
        )

        if (field.kind === "boolean") {
          return (
            <div key={field.name} className="grid gap-3">
              {commonLabel}
              <label className="flex items-center gap-3 text-sm">
                <Checkbox
                  checked={Boolean(value)}
                  onCheckedChange={(checked) => form.setValue(field.name, checked === true)}
                />
                <span>{Boolean(value) ? "Yes" : "No"}</span>
              </label>
              {error ? <p className="text-sm text-[color:var(--resource-danger)]">{error}</p> : null}
            </div>
          )
        }

        if (field.kind === "select") {
          return (
            <div key={field.name} className="grid gap-2">
              {commonLabel}
              <Select
                value={typeof value === "string" ? value : ""}
                onValueChange={(nextValue) => form.setValue(field.name, nextValue)}
              >
                <SelectTrigger id={field.name}>
                  <SelectValue placeholder={`Select ${field.label.toLowerCase()}`} />
                </SelectTrigger>
                <SelectContent>
                  {field.options.map((option) => (
                    <SelectItem key={option} value={option}>
                      {option}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
              {error ? <p className="text-sm text-[color:var(--resource-danger)]">{error}</p> : null}
            </div>
          )
        }

        if (field.kind === "foreign-key") {
          return (
            <div key={field.name} className="grid gap-2">
              {commonLabel}
              <LemmaForeignKeySelect
                client={client}
                podId={podId}
                tableName={tableName}
                columnName={field.name}
                value={typeof value === "string" ? value : value ? String(value) : ""}
                onValueChange={(nextValue: string) => form.setValue(field.name, nextValue)}
              />
              {error ? <p className="text-sm text-[color:var(--resource-danger)]">{error}</p> : null}
            </div>
          )
        }

        if (field.kind === "json" || field.kind === "textarea") {
          return (
            <div key={field.name} className="grid gap-2">
              {commonLabel}
              <Textarea
                id={field.name}
                rows={field.kind === "json" ? 8 : 4}
                value={typeof value === "string" ? value : ""}
                onChange={(event) => form.setValue(field.name, event.target.value)}
              />
              {error ? <p className="text-sm text-[color:var(--resource-danger)]">{error}</p> : null}
            </div>
          )
        }

        return (
          <div key={field.name} className="grid gap-2">
            {commonLabel}
            <Input
              id={field.name}
              type={
                field.kind === "number"
                  ? "number"
                  : field.kind === "date"
                    ? "date"
                    : field.kind === "datetime"
                      ? "datetime-local"
                      : "text"
              }
              value={typeof value === "string" ? value : value ? String(value) : ""}
              onChange={(event) => form.setValue(field.name, event.target.value)}
            />
            {error ? <p className="text-sm text-[color:var(--resource-danger)]">{error}</p> : null}
          </div>
        )
      })}

      {appearance === "card" ? (
        <div className="flex items-center gap-2 pt-2">
          <Button disabled={form.isSubmitting || form.isLoadingSchema || form.isLoadingRecord} type="submit">
            {form.isSubmitting ? "Saving…" : submitLabel}
          </Button>
          {showReset ? (
            <Button
              disabled={form.isSubmitting}
              onClick={() => form.reset()}
              type="button"
              variant="outline"
            >
              {resetLabel}
            </Button>
          ) : null}
        </div>
      ) : null}
    </form>
  )

  if (appearance === "modal") {
    return (
      <div className="grid h-full min-h-0 grid-rows-[auto_minmax(0,1fr)_auto] bg-[var(--resource-surface)]">
        <div className="flex items-start justify-between gap-4 border-b border-[color:var(--resource-border)] px-6 py-5">
          {header}
          <Button onClick={onCancel} type="button" variant="ghost">
            Close
          </Button>
        </div>
        <div className="min-h-0 overflow-y-auto px-6 py-6">
          {body}
        </div>
        <div className="flex items-center justify-end gap-3 border-t border-[color:var(--resource-border)] px-6 py-5">
          <Button onClick={onCancel} type="button" variant="ghost">
            {cancelLabel}
          </Button>
          <Button
            disabled={form.isSubmitting || form.isLoadingSchema || form.isLoadingRecord}
            onClick={() => {
              void form.submit()
            }}
            type="button"
          >
            {form.isSubmitting ? "Saving…" : submitLabel}
          </Button>
        </div>
      </div>
    )
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle>{title ?? `${recordId ? "Edit" : "Create"} ${tableName}`}</CardTitle>
        <CardDescription>
          {description ?? "Schema-aware form powered by lemma-sdk/react."}
        </CardDescription>
      </CardHeader>
      <CardContent>{body}</CardContent>
    </Card>
  )
}

"use client"

import * as React from "react"
import type { LemmaClient } from "lemma-sdk"
import { useRecords } from "lemma-sdk/react"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"

export interface LemmaRecordPickerProps {
  client: LemmaClient
  podId?: string
  tableName: string
  value?: string
  onValueChange?: (value: string) => void
  title?: string
  description?: string
  placeholder?: string
  search?: string
  onSearchChange?: (value: string) => void
  searchPlaceholder?: string
  searchFields?: string[]
  labelFields?: string[]
  limit?: number
  records?: Record<string, unknown>[]
  isLoading?: boolean
  error?: Error | null
  onRefresh?: () => void
}

const EMPTY_LABEL_FIELDS: string[] = []

function summarizeRecord(record: Record<string, unknown>, labelFields: string[]): string {
  const candidates = [
    ...labelFields,
    "title",
    "name",
    "label",
    "email",
    "id",
  ]

  for (const field of candidates) {
    const value = record[field]
    if (typeof value === "string" && value.trim().length > 0) return value
    if (typeof value === "number") return String(value)
  }

  try {
    return JSON.stringify(record)
  } catch {
    return "Untitled record"
  }
}

export function LemmaRecordPicker({
  client,
  podId,
  tableName,
  value,
  onValueChange,
  title = "Record Picker",
  description = "Jump to a specific record in the selected table.",
  placeholder = "Select a record",
  search,
  onSearchChange,
  searchPlaceholder = "Search loaded records…",
  searchFields,
  labelFields = EMPTY_LABEL_FIELDS,
  limit = 50,
  records,
  isLoading,
  error,
  onRefresh,
}: LemmaRecordPickerProps) {
  const [internalSearch, setInternalSearch] = React.useState("")
  const activeSearch = search ?? internalSearch
  const deferredSearch = React.useDeferredValue(activeSearch)
  const trimmedTableName = tableName.trim()
  const recordsState = useRecords({
    client,
    podId,
    tableName: trimmedTableName,
    enabled: trimmedTableName.length > 0 && !records,
    limit,
  })

  const effectiveRecords = records ?? recordsState.records
  const effectiveIsLoading = isLoading ?? recordsState.isLoading
  const effectiveError = error ?? recordsState.error

  const filteredRecords = React.useMemo(() => {
    const normalizedSearch = deferredSearch.trim().toLowerCase()
    if (!normalizedSearch) return effectiveRecords

    const fields = searchFields?.length
      ? searchFields
      : Array.from(new Set([...labelFields, "title", "name", "label", "email", "id"]))

    return effectiveRecords.filter((record) => fields.some((field) => {
      const fieldValue = record[field]
      if (typeof fieldValue === "string") return fieldValue.toLowerCase().includes(normalizedSearch)
      if (typeof fieldValue === "number" || typeof fieldValue === "boolean") {
        return String(fieldValue).toLowerCase().includes(normalizedSearch)
      }
      return false
    }))
  }, [deferredSearch, effectiveRecords, labelFields, searchFields])

  return (
    <Card>
      <CardHeader>
        <div className="flex items-start justify-between gap-3">
          <div className="grid gap-1">
            <CardTitle>{title}</CardTitle>
            <CardDescription>{description}</CardDescription>
          </div>
          <Button
            disabled={effectiveIsLoading || trimmedTableName.length === 0}
            onClick={() => {
              if (onRefresh) {
                onRefresh()
                return
              }
              void recordsState.refresh()
            }}
            variant="outline"
          >
            {effectiveIsLoading ? "Refreshing…" : "Refresh"}
          </Button>
        </div>
      </CardHeader>
      <CardContent className="grid gap-3">
        {effectiveError ? (
          <div className="rounded-md border border-[color:var(--resource-danger-border)] bg-[var(--resource-danger-soft)] px-3 py-2 text-sm text-[color:var(--resource-danger)]">
            {effectiveError.message}
          </div>
        ) : null}

        <Input
          onChange={(event) => {
            if (onSearchChange) {
              onSearchChange(event.target.value)
              return
            }
            setInternalSearch(event.target.value)
          }}
          placeholder={searchPlaceholder}
          value={activeSearch}
        />

        <Select
          disabled={trimmedTableName.length === 0 || filteredRecords.length === 0}
          value={value ?? ""}
          onValueChange={onValueChange}
        >
          <SelectTrigger id="lemma-record-picker">
            <SelectValue placeholder={placeholder} />
          </SelectTrigger>
          <SelectContent>
            {filteredRecords.map((record) => {
              const id = typeof record.id === "string" ? record.id : String(record.id ?? "")
              return (
                <SelectItem key={id} value={id}>
                  {summarizeRecord(record, labelFields)}
                </SelectItem>
              )
            })}
          </SelectContent>
        </Select>

        <p className="text-xs text-[color:var(--resource-muted)]">
          {trimmedTableName.length === 0
            ? "Select a table first."
            : `${filteredRecords.length} record${filteredRecords.length === 1 ? "" : "s"} available`}
        </p>
      </CardContent>
    </Card>
  )
}

"use client"

import * as React from "react"
import type { LemmaClient } from "lemma-sdk"
import { useRecords, useTable } from "lemma-sdk/react"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { Checkbox } from "@/components/ui/checkbox"

type LemmaRecordsTableButtonVariant =
  | "default"
  | "outline"
  | "secondary"
  | "ghost"
  | "destructive"
  | "link"

export interface LemmaRecordsTableColumn {
  name: string
  label?: string
  description?: string
  type?: string
  width?: number | string
  minWidth?: number | string
  align?: "start" | "center" | "end"
  searchable?: boolean
  hideable?: boolean
  hidden?: boolean
  headerClassName?: string
  cellClassName?: string
  renderCell?: (args: {
    record: Record<string, unknown>
    value: unknown
    column: LemmaRecordsTableColumn
    rowIndex: number
    isSelected: boolean
  }) => React.ReactNode
}

export interface LemmaRecordsTableRowAction {
  key: string
  label: string
  onClick: (record: Record<string, unknown>) => void
  disabled?: (record: Record<string, unknown>) => boolean
  variant?: LemmaRecordsTableButtonVariant
}

export interface LemmaRecordsTableProps {
  client: LemmaClient
  podId?: string
  tableName: string
  title?: string
  description?: string
  limit?: number
  records?: Record<string, unknown>[]
  isLoading?: boolean
  error?: Error | null
  onRefresh?: () => void
  columnNames?: string[]
  columns?: LemmaRecordsTableColumn[]
  maxColumns?: number
  search?: string
  searchFields?: string[]
  selectedRecordId?: string | null
  recordIdField?: string
  getRecordId?: (record: Record<string, unknown>) => string
  emptyText?: string
  onRowSelect?: (record: Record<string, unknown>) => void
  showSelection?: boolean
  selectedRecordIds?: string[]
  onSelectedRecordIdsChange?: (recordIds: string[]) => void
  pageIndex?: number
  pageSize?: number
  totalCount?: number
  hasNextPage?: boolean
  onPreviousPage?: () => void
  onNextPage?: () => void
  density?: "compact" | "comfortable"
  hiddenColumnNames?: string[]
  defaultHiddenColumnNames?: string[]
  onHiddenColumnNamesChange?: (hiddenColumnNames: string[]) => void
  allowColumnVisibility?: boolean
  columnVisibilityLabel?: string
  onCreateRecord?: () => void
  createButtonLabel?: string
  rowActions?: LemmaRecordsTableRowAction[]
  rowActionsLabel?: string
}

function formatValue(value: unknown): string {
  if (typeof value === "string") return value
  if (typeof value === "number" || typeof value === "boolean") return String(value)
  if (value === null || typeof value === "undefined") return "—"

  try {
    return JSON.stringify(value)
  } catch {
    return String(value)
  }
}

function readRecordId(
  record: Record<string, unknown>,
  recordIdField: string,
  getRecordId?: (record: Record<string, unknown>) => string,
): string {
  if (getRecordId) {
    const customId = getRecordId(record)
    return typeof customId === "string" ? customId : ""
  }

  const value = record[recordIdField]
  if (typeof value === "string") return value
  if (typeof value === "number") return String(value)
  return ""
}

function sentenceCase(value: string): string {
  return value
    .replace(/[_\.]/g, " ")
    .replace(/\s+/g, " ")
    .trim()
    .replace(/\b\w/g, (match) => match.toUpperCase())
}

function normalizeWidth(value?: number | string): string | undefined {
  if (typeof value === "number") return `${value}px`
  return value
}

function alignClassName(align: LemmaRecordsTableColumn["align"]): string {
  if (align === "center") return "text-center"
  if (align === "end") return "text-right"
  return "text-left"
}

export function LemmaRecordsTable({
  client,
  podId,
  tableName,
  title,
  description,
  limit = 10,
  records,
  isLoading,
  error,
  onRefresh,
  columnNames,
  columns,
  maxColumns = 6,
  search,
  searchFields,
  selectedRecordId,
  recordIdField = "id",
  getRecordId,
  emptyText = "No records found for this table.",
  onRowSelect,
  showSelection = false,
  selectedRecordIds,
  onSelectedRecordIdsChange,
  pageIndex = 0,
  pageSize = limit,
  totalCount,
  hasNextPage = false,
  onPreviousPage,
  onNextPage,
  density = "compact",
  hiddenColumnNames,
  defaultHiddenColumnNames = [],
  onHiddenColumnNamesChange,
  allowColumnVisibility = false,
  columnVisibilityLabel = "Columns",
  onCreateRecord,
  createButtonLabel = "New Record",
  rowActions = [],
  rowActionsLabel = "Actions",
}: LemmaRecordsTableProps) {
  const trimmedTableName = tableName.trim()
  const tableState = useTable({
    client,
    podId,
    tableName: trimmedTableName,
    enabled: trimmedTableName.length > 0,
  })
  const recordsState = useRecords({
    client,
    podId,
    tableName: trimmedTableName,
    enabled: trimmedTableName.length > 0 && !records,
    limit,
  })
  const effectiveRecords = records ?? recordsState.records
  const effectiveIsLoading = isLoading ?? recordsState.isLoading
  const effectiveError = error ?? recordsState.error
  const deferredSearch = React.useDeferredValue(search ?? "")
  const [isColumnEditorOpen, setIsColumnEditorOpen] = React.useState(false)
  const [internalHiddenColumnNames, setInternalHiddenColumnNames] = React.useState(defaultHiddenColumnNames)

  const setResolvedHiddenColumnNames = React.useCallback((nextHiddenColumnNames: string[]) => {
    if (typeof hiddenColumnNames === "undefined") {
      setInternalHiddenColumnNames(nextHiddenColumnNames)
    }
    onHiddenColumnNamesChange?.(nextHiddenColumnNames)
  }, [hiddenColumnNames, onHiddenColumnNamesChange])

  const resolvedHiddenColumnNames = hiddenColumnNames ?? internalHiddenColumnNames

  const allColumns = React.useMemo<LemmaRecordsTableColumn[]>(() => {
    if (columns?.length) {
      return columns
    }

    if (columnNames?.length) {
      return columnNames.map((columnName) => {
        const schemaColumn = tableState.table?.columns.find((column) => column.name === columnName)
        return {
          name: columnName,
          label: sentenceCase(columnName),
          type: schemaColumn?.type?.toLowerCase() ?? "text",
        } satisfies LemmaRecordsTableColumn
      })
    }

    const schemaColumns = tableState.table?.columns
      .filter((column) => column.name !== "created_at" && column.name !== "updated_at")
      .slice(0, maxColumns)
      .map((column) => ({
        name: column.name,
        label: sentenceCase(column.name),
        type: column.type.toLowerCase(),
      } satisfies LemmaRecordsTableColumn))

    if (schemaColumns && schemaColumns.length > 0) {
      return schemaColumns
    }

    const discoveredKeys = Array.from(
      new Set(effectiveRecords.flatMap((record) => Object.keys(record))),
    ).slice(0, maxColumns)

    return discoveredKeys.map((columnName) => ({
      name: columnName,
      label: sentenceCase(columnName),
      type: "text",
    } satisfies LemmaRecordsTableColumn))
  }, [columnNames, columns, effectiveRecords, maxColumns, tableState.table])

  const hiddenColumnNameSet = React.useMemo(() => {
    const names = new Set(resolvedHiddenColumnNames)
    allColumns.forEach((column) => {
      if (column.hidden) {
        names.add(column.name)
      }
    })
    return names
  }, [allColumns, resolvedHiddenColumnNames])

  const visibleColumns = React.useMemo(
    () => allColumns.filter((column) => !hiddenColumnNameSet.has(column.name)),
    [allColumns, hiddenColumnNameSet],
  )

  const searchableFieldNames = React.useMemo(() => {
    if (searchFields?.length) return searchFields
    return allColumns
      .filter((column) => column.searchable !== false)
      .map((column) => column.name)
  }, [allColumns, searchFields])

  const filteredRecords = React.useMemo(() => {
    const normalizedSearch = deferredSearch.trim().toLowerCase()
    if (!normalizedSearch) return effectiveRecords

    return effectiveRecords.filter((record) => searchableFieldNames.some((field) => {
      const value = record[field]
      if (typeof value === "string") return value.toLowerCase().includes(normalizedSearch)
      if (typeof value === "number" || typeof value === "boolean") {
        return String(value).toLowerCase().includes(normalizedSearch)
      }
      return false
    }))
  }, [deferredSearch, effectiveRecords, searchableFieldNames])

  const selectedIdSet = React.useMemo(
    () => new Set(selectedRecordIds ?? []),
    [selectedRecordIds],
  )
  const visibleSelectableIds = React.useMemo(
    () => filteredRecords
      .map((record) => readRecordId(record, recordIdField, getRecordId))
      .filter((value) => value.length > 0),
    [filteredRecords, getRecordId, recordIdField],
  )
  const allVisibleSelected = visibleSelectableIds.length > 0
    && visibleSelectableIds.every((recordId) => selectedIdSet.has(recordId))
  const selectionEnabled = showSelection && !!onSelectedRecordIdsChange
  const resolvedTotalCount = typeof totalCount === "number" ? totalCount : filteredRecords.length
  const rangeStart = resolvedTotalCount === 0 ? 0 : (pageIndex * pageSize) + 1
  const rangeEnd = Math.min((pageIndex * pageSize) + filteredRecords.length, resolvedTotalCount)
  const rowPadding = density === "compact" ? "py-3" : "py-4"
  const hasRowActions = rowActions.length > 0

  const toggleRecordSelection = React.useCallback((recordId: string, checked: boolean) => {
    if (!onSelectedRecordIdsChange) return

    const nextSelection = new Set(selectedRecordIds ?? [])
    if (checked) {
      nextSelection.add(recordId)
    } else {
      nextSelection.delete(recordId)
    }
    onSelectedRecordIdsChange(Array.from(nextSelection))
  }, [onSelectedRecordIdsChange, selectedRecordIds])

  const toggleVisibleSelection = React.useCallback((checked: boolean) => {
    if (!onSelectedRecordIdsChange) return

    const nextSelection = new Set(selectedRecordIds ?? [])
    visibleSelectableIds.forEach((recordId) => {
      if (checked) {
        nextSelection.add(recordId)
      } else {
        nextSelection.delete(recordId)
      }
    })
    onSelectedRecordIdsChange(Array.from(nextSelection))
  }, [onSelectedRecordIdsChange, selectedRecordIds, visibleSelectableIds])

  if (!trimmedTableName) {
    return (
      <Card>
        <CardHeader>
          <CardTitle>{title ?? "Records Table"}</CardTitle>
          <CardDescription>{description ?? "Select a table to preview its records."}</CardDescription>
        </CardHeader>
      </Card>
    )
  }

  return (
    <>
      <Card>
        <CardHeader>
          <div className="flex items-start justify-between gap-3">
            <div className="grid gap-1">
              <CardTitle>{title ?? `Records: ${trimmedTableName}`}</CardTitle>
              <CardDescription>
                {description ?? `Preview the latest ${limit} records from this table.`}
              </CardDescription>
            </div>
            <div className="flex flex-wrap items-center justify-end gap-2">
              {onCreateRecord ? (
                <Button onClick={onCreateRecord} type="button">
                  {createButtonLabel}
                </Button>
              ) : null}
              {allowColumnVisibility && allColumns.length > 0 ? (
                <Button
                  onClick={() => setIsColumnEditorOpen(true)}
                  type="button"
                  variant="outline"
                >
                  {columnVisibilityLabel}
                </Button>
              ) : null}
              <Button
                disabled={effectiveIsLoading}
                onClick={() => {
                  if (onRefresh) {
                    onRefresh()
                    return
                  }
                  void recordsState.refresh()
                }}
                variant="outline"
              >
                {effectiveIsLoading ? "Refreshing…" : "Refresh"}
              </Button>
            </div>
          </div>
        </CardHeader>
        <CardContent className="grid gap-4">
          {effectiveError ? (
            <div className="rounded-md border border-[color:var(--resource-danger-border)] bg-[var(--resource-danger-soft)] px-3 py-2 text-sm text-[color:var(--resource-danger)]">
              {effectiveError.message}
            </div>
          ) : null}

          {effectiveIsLoading && filteredRecords.length === 0 ? (
            <div className="rounded-md border border-dashed border-[color:var(--resource-border)] bg-[var(--resource-surface-alt)] px-3 py-6 text-sm text-[color:var(--resource-muted)]">
              Loading records…
            </div>
          ) : null}

          {!effectiveIsLoading && filteredRecords.length === 0 ? (
            <div className="rounded-md border border-dashed border-[color:var(--resource-border)] bg-[var(--resource-surface-alt)] px-3 py-6 text-sm text-[color:var(--resource-muted)]">
              {emptyText}
            </div>
          ) : null}

          {!effectiveIsLoading && filteredRecords.length > 0 && visibleColumns.length === 0 ? (
            <div className="rounded-md border border-dashed border-[color:var(--resource-border)] bg-[var(--resource-surface-alt)] px-3 py-6 text-sm text-[color:var(--resource-muted)]">
              All columns are currently hidden. Reopen the column picker to show fields.
            </div>
          ) : null}

          {filteredRecords.length > 0 && visibleColumns.length > 0 ? (
            <div className="overflow-x-auto rounded-[8px] border border-[color:var(--resource-border)] bg-[var(--resource-surface)]">
              <table className="min-w-full border-collapse text-sm">
                <thead className="sticky top-0 z-10 bg-[var(--resource-table-header)] text-left text-[color:var(--resource-muted-strong)]">
                  <tr>
                    {selectionEnabled ? (
                      <th className="w-10 px-3 py-3 font-medium">
                        <Checkbox
                          aria-label="Select visible records"
                          checked={allVisibleSelected}
                          onCheckedChange={(checked) => toggleVisibleSelection(checked === true)}
                        />
                      </th>
                    ) : null}
                    {visibleColumns.map((column) => (
                      <th
                        className={[
                          "px-4 py-3 font-medium",
                          alignClassName(column.align),
                          column.headerClassName ?? "",
                        ].join(" ")}
                        key={column.name}
                        style={{
                          minWidth: normalizeWidth(column.minWidth),
                          width: normalizeWidth(column.width),
                        }}
                      >
                        <div className="grid gap-1">
                          <span className="text-base font-medium text-[color:var(--resource-text)]">
                            {column.label ?? sentenceCase(column.name)}
                          </span>
                          <div className="flex flex-wrap items-center gap-2">
                            <span className="inline-flex w-fit rounded-[6px] bg-[var(--resource-badge)] px-2 py-0.5 text-[11px] font-medium uppercase tracking-[0.08em] text-[color:var(--resource-badge-text)]">
                              {column.type ?? "text"}
                            </span>
                            {column.description ? (
                              <span className="text-xs text-[color:var(--resource-muted)]">
                                {column.description}
                              </span>
                            ) : null}
                          </div>
                        </div>
                      </th>
                    ))}
                    {hasRowActions ? (
                      <th className="px-4 py-3 text-right font-medium text-[color:var(--resource-text)]">
                        {rowActionsLabel}
                      </th>
                    ) : null}
                  </tr>
                </thead>
                <tbody>
                  {filteredRecords.map((record, index) => {
                    const rowId = readRecordId(record, recordIdField, getRecordId)
                    const isSelected = !!selectedRecordId && rowId === selectedRecordId

                    return (
                      <tr
                        className={[
                          "border-t border-[color:var(--resource-border)] align-top text-[color:var(--resource-text)]",
                          onRowSelect ? "cursor-pointer transition-colors hover:bg-[var(--resource-table-row-hover)]" : "",
                          isSelected ? "bg-[var(--resource-table-row-selected)] shadow-[inset_0_0_0_1px_var(--resource-ring)]" : "",
                        ].join(" ")}
                        key={rowId || index}
                        onClick={onRowSelect ? () => onRowSelect(record) : undefined}
                      >
                        {selectionEnabled ? (
                          <td className={`px-3 ${rowPadding}`}>
                            <Checkbox
                              aria-label={`Select record ${rowId || index + 1}`}
                              checked={selectedIdSet.has(rowId)}
                              onCheckedChange={(checked) => {
                                if (!rowId) return
                                toggleRecordSelection(rowId, checked === true)
                              }}
                              onClick={(event) => event.stopPropagation()}
                            />
                          </td>
                        ) : null}
                        {visibleColumns.map((column) => {
                          const value = record[column.name]
                          const renderedValue = column.renderCell
                            ? column.renderCell({
                                record,
                                value,
                                column,
                                rowIndex: index,
                                isSelected,
                              })
                            : formatValue(value)

                          return (
                            <td
                              className={[
                                `max-w-[360px] px-4 ${rowPadding}`,
                                alignClassName(column.align),
                                column.cellClassName ?? "",
                              ].join(" ")}
                              key={column.name}
                              style={{
                                minWidth: normalizeWidth(column.minWidth),
                                width: normalizeWidth(column.width),
                              }}
                            >
                              <div className="truncate font-medium text-[color:var(--resource-text)]" title={formatValue(value)}>
                                {renderedValue}
                              </div>
                            </td>
                          )
                        })}
                        {hasRowActions ? (
                          <td className={`px-4 ${rowPadding}`}>
                            <div className="flex items-center justify-end gap-2">
                              {rowActions.map((action) => (
                                <Button
                                  disabled={action.disabled?.(record) ?? false}
                                  key={action.key}
                                  onClick={(event) => {
                                    event.stopPropagation()
                                    action.onClick(record)
                                  }}
                                  size="sm"
                                  type="button"
                                  variant={action.variant ?? "outline"}
                                >
                                  {action.label}
                                </Button>
                              ))}
                            </div>
                          </td>
                        ) : null}
                      </tr>
                    )
                  })}
                </tbody>
              </table>
            </div>
          ) : null}

          {resolvedTotalCount > 0 && (onPreviousPage || onNextPage) ? (
            <div className="flex flex-col gap-3 border-t border-[color:var(--resource-border)] pt-4 text-sm text-[color:var(--resource-muted-strong)] md:flex-row md:items-center md:justify-between">
              <div>
                Showing {rangeStart}-{rangeEnd} of {resolvedTotalCount}
              </div>
              <div className="flex items-center gap-2">
                <Button
                  disabled={pageIndex === 0}
                  onClick={onPreviousPage}
                  variant="outline"
                >
                  Previous
                </Button>
                <div className="text-xs text-[color:var(--resource-muted)]">Page {pageIndex + 1}</div>
                <Button
                  disabled={!hasNextPage}
                  onClick={onNextPage}
                  variant="outline"
                >
                  Next
                </Button>
              </div>
            </div>
          ) : null}
        </CardContent>
      </Card>

      {isColumnEditorOpen ? (
        <div className="fixed inset-0 z-50 flex items-start justify-center bg-black/20 px-4 py-8 backdrop-blur-[1px]">
          <div className="w-full max-w-2xl rounded-[8px] border border-[color:var(--resource-border)] bg-[var(--resource-surface)] shadow-[0_28px_90px_-40px_var(--resource-shadow-lg)]">
            <div className="flex items-start justify-between gap-4 border-b border-[color:var(--resource-border)] px-6 py-5">
              <div className="grid gap-2">
                <h3 className="text-2xl font-semibold text-[color:var(--resource-text)]">
                  Choose Columns
                </h3>
                <p className="text-sm uppercase tracking-[0.18em] text-[color:var(--resource-muted-strong)]">
                  Show or hide fields for this table view
                </p>
              </div>
              <Button
                onClick={() => setIsColumnEditorOpen(false)}
                type="button"
                variant="ghost"
              >
                Close
              </Button>
            </div>
            <div className="grid gap-3 px-6 py-6">
              {allColumns.map((column) => {
                const isHideable = column.hideable !== false
                const isChecked = !hiddenColumnNameSet.has(column.name)
                return (
                  <label
                    className={[
                      "flex items-start gap-3 rounded-[8px] border border-[color:var(--resource-border)] px-4 py-3",
                      isHideable ? "cursor-pointer bg-[var(--resource-surface)]" : "bg-[var(--resource-surface-alt)] opacity-70",
                    ].join(" ")}
                    key={column.name}
                  >
                    <Checkbox
                      checked={isChecked}
                      disabled={!isHideable}
                      onCheckedChange={(checked) => {
                        if (!isHideable) return

                        const nextHiddenColumnNames = new Set(hiddenColumnNameSet)
                        if (checked === true) {
                          nextHiddenColumnNames.delete(column.name)
                        } else {
                          nextHiddenColumnNames.add(column.name)
                        }
                        setResolvedHiddenColumnNames(Array.from(nextHiddenColumnNames))
                      }}
                    />
                    <div className="grid gap-1">
                      <div className="flex flex-wrap items-center gap-2">
                        <span className="font-medium text-[color:var(--resource-text)]">
                          {column.label ?? sentenceCase(column.name)}
                        </span>
                        <span className="inline-flex rounded-[6px] bg-[var(--resource-badge)] px-2 py-0.5 text-[11px] font-medium uppercase tracking-[0.08em] text-[color:var(--resource-badge-text)]">
                          {column.type ?? "text"}
                        </span>
                      </div>
                      {column.description ? (
                        <p className="text-sm text-[color:var(--resource-muted)]">
                          {column.description}
                        </p>
                      ) : null}
                    </div>
                  </label>
                )
              })}
            </div>
            <div className="flex items-center justify-end gap-3 border-t border-[color:var(--resource-border)] px-6 py-5">
              <Button
                onClick={() => setResolvedHiddenColumnNames([])}
                type="button"
                variant="ghost"
              >
                Show All
              </Button>
              <Button
                onClick={() => setIsColumnEditorOpen(false)}
                type="button"
              >
                Done
              </Button>
            </div>
          </div>
        </div>
      ) : null}
    </>
  )
}

